import{_ as l}from"./plugin-vue_export-helper.21dcd24c.js";import{r as n,o,c as u,a as r,b as a,e as i,d as t}from"./app.dbe422c1.js";var d="/flutter-docs/assets/1-1.d051f567.png";const s={},p=i('<h1 id="_1-2-\u521D\u8BC6-flutter" tabindex="-1"><a class="header-anchor" href="#_1-2-\u521D\u8BC6-flutter" aria-hidden="true">#</a> 1.2 \u521D\u8BC6 Flutter</h1><h2 id="_1-2-1-flutter-\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#_1-2-1-flutter-\u7B80\u4ECB" aria-hidden="true">#</a> 1.2.1 Flutter \u7B80\u4ECB</h2><p>Flutter \u662F Google \u63A8\u51FA\u5E76\u5F00\u6E90\u7684\u79FB\u52A8\u5E94\u7528\u5F00\u53D1\u6846\u67B6\uFF0C\u4E3B\u6253\u8DE8\u5E73\u53F0\u3001\u9AD8\u4FDD\u771F\u3001\u9AD8\u6027\u80FD\u3002\u5F00\u53D1\u8005\u53EF\u4EE5\u901A\u8FC7 Dart \u8BED\u8A00\u5F00\u53D1 App\uFF0C\u4E00\u5957\u4EE3\u7801\u540C\u65F6\u8FD0\u884C\u5728 iOS \u548C Android\u5E73\u53F0\u3002 Flutter \u63D0\u4F9B\u4E86\u4E30\u5BCC\u7684\u7EC4\u4EF6\u3001\u63A5\u53E3\uFF0C\u5F00\u53D1\u8005\u53EF\u4EE5\u5F88\u5FEB\u5730\u4E3A Flutter \u6DFB\u52A0 Native \u6269\u5C55\u3002</p><h4 id="\u8DE8\u5E73\u53F0\u81EA\u7ED8\u5F15\u64CE" tabindex="-1"><a class="header-anchor" href="#\u8DE8\u5E73\u53F0\u81EA\u7ED8\u5F15\u64CE" aria-hidden="true">#</a> \u8DE8\u5E73\u53F0\u81EA\u7ED8\u5F15\u64CE</h4><p>Flutter \u4E0E\u7528\u4E8E\u6784\u5EFA\u79FB\u52A8\u5E94\u7528\u7A0B\u5E8F\u7684\u5176\u5B83\u5927\u591A\u6570\u6846\u67B6\u4E0D\u540C\uFF0C\u56E0\u4E3A Flutter \u65E2\u4E0D\u4F7F\u7528 WebView\uFF0C\u4E5F\u4E0D\u4F7F\u7528\u64CD\u4F5C\u7CFB\u7EDF\u7684\u539F\u751F\u63A7\u4EF6\u3002 \u76F8\u53CD\uFF0CFlutter \u4F7F\u7528\u81EA\u5DF1\u7684\u9AD8\u6027\u80FD\u6E32\u67D3\u5F15\u64CE\u6765\u7ED8\u5236 Widget\uFF08\u7EC4\u4EF6\uFF09\u3002\u8FD9\u6837\u4E0D\u4EC5\u53EF\u4EE5\u4FDD\u8BC1\u5728 Android \u548CiOS \u4E0A UI \u7684\u4E00\u81F4\u6027\uFF0C\u4E5F\u53EF\u4EE5\u907F\u514D\u5BF9\u539F\u751F\u63A7\u4EF6\u4F9D\u8D56\u800C\u5E26\u6765\u7684\u9650\u5236\u53CA\u9AD8\u6602\u7684\u7EF4\u62A4\u6210\u672C\u3002</p><p>Flutter \u5E95\u5C42\u4F7F\u7528 Skia \u4F5C\u4E3A\u5176 2D \u6E32\u67D3\u5F15\u64CE\uFF0CSkia \u662F Google\u7684\u4E00\u4E2A 2D \u56FE\u5F62\u5904\u7406\u51FD\u6570\u5E93\uFF0C\u5305\u542B\u5B57\u578B\u3001\u5750\u6807\u8F6C\u6362\uFF0C\u4EE5\u53CA\u70B9\u9635\u56FE\uFF0C\u5B83\u4EEC\u90FD\u6709\u9AD8\u6548\u80FD\u4E14\u7B80\u6D01\u7684\u8868\u73B0\u3002Skia \u662F\u8DE8\u5E73\u53F0\u7684\uFF0C\u5E76\u63D0\u4F9B\u4E86\u975E\u5E38\u53CB\u597D\u7684 API\uFF0C\u76EE\u524D Google Chrome\u6D4F\u89C8\u5668\u548C Android \u5747\u91C7\u7528 Skia \u4F5C\u4E3A\u5176 2D \u7ED8\u56FE\u5F15\u64CE\u3002</p><p>\u76EE\u524D Flutter \u5DF2\u7ECF\u652F\u6301 iOS\u3001Android\u3001Web\u3001Windows\u3001macOS\u3001Linux\u3001Fuchsia\uFF08Google\u65B0\u7684\u81EA\u7814\u64CD\u4F5C\u7CFB\u7EDF\uFF09\u7B49\u4F17\u591A\u5E73\u53F0\uFF0C\u4F46\u672C\u4E66\u7684\u793A\u4F8B\u548C\u4ECB\u7ECD\u4E3B\u8981\u662F\u57FA\u4E8E iOS \u548C Android \u5E73\u53F0\u7684\uFF0C\u5176\u5B83\u5E73\u53F0\u8BFB\u8005\u53EF\u4EE5\u81EA\u884C\u4E86\u89E3\u3002</p><h4 id="\u9AD8\u6027\u80FD" tabindex="-1"><a class="header-anchor" href="#\u9AD8\u6027\u80FD" aria-hidden="true">#</a> \u9AD8\u6027\u80FD</h4><p>Flutter \u9AD8\u6027\u80FD\u4E3B\u8981\u9760\u4E24\u70B9\u6765\u4FDD\u8BC1\uFF1A</p><p>\u7B2C\u4E00\uFF1AFlutter APP \u91C7\u7528 Dart \u8BED\u8A00\u5F00\u53D1\u3002Dart \u5728 JIT\uFF08\u5373\u65F6\u7F16\u8BD1\uFF09\u6A21\u5F0F\u4E0B\uFF0C\u6267\u884C\u901F\u5EA6\u4E0E JavaScript \u57FA\u672C\u6301\u5E73\u3002\u4F46\u662F Dart \u652F\u6301 AOT\uFF0C\u5F53\u4EE5 AOT\u6A21\u5F0F\u8FD0\u884C\u65F6\uFF0CJavaScript \u4FBF\u8FDC\u8FDC\u8FFD\u4E0D\u4E0A\u4E86\u3002\u6267\u884C\u901F\u5EA6\u7684\u63D0\u5347\u5BF9\u9AD8\u5E27\u7387\u4E0B\u7684\u89C6\u56FE\u6570\u636E\u8BA1\u7B97\u5F88\u6709\u5E2E\u52A9\u3002</p><p>\u7B2C\u4E8C\uFF1AFlutter \u4F7F\u7528\u81EA\u5DF1\u7684\u6E32\u67D3\u5F15\u64CE\u6765\u7ED8\u5236 UI \uFF0C\u5E03\u5C40\u6570\u636E\u7B49\u7531 Dart \u8BED\u8A00\u76F4\u63A5\u63A7\u5236\uFF0C\u6240\u4EE5\u5728\u5E03\u5C40\u8FC7\u7A0B\u4E2D\u4E0D\u9700\u8981\u50CF RN \u90A3\u6837\u8981\u5728 JavaScript \u548C Native \u4E4B\u95F4\u901A\u4FE1\uFF0C\u8FD9\u5728\u4E00\u4E9B\u6ED1\u52A8\u548C\u62D6\u52A8\u7684\u573A\u666F\u4E0B\u5177\u6709\u660E\u663E\u4F18\u52BF\uFF0C\u56E0\u4E3A\u5728\u6ED1\u52A8\u548C\u62D6\u52A8\u8FC7\u7A0B\u5F80\u5F80\u90FD\u4F1A\u5F15\u8D77\u5E03\u5C40\u53D1\u751F\u53D8\u5316\uFF0C\u6240\u4EE5 JavaScript \u9700\u8981\u548C Native \u4E4B\u95F4\u4E0D\u505C\u7684\u540C\u6B65\u5E03\u5C40\u4FE1\u606F\uFF0C\u8FD9\u548C\u5728\u6D4F\u89C8\u5668\u4E2DJavaScript \u9891\u7E41\u64CD\u4F5C DOM \u6240\u5E26\u6765\u7684\u95EE\u9898\u662F\u7C7B\u4F3C\u7684\uFF0C\u90FD\u4F1A\u5BFC\u81F4\u6BD4\u8F83\u53EF\u89C2\u7684\u6027\u80FD\u5F00\u9500\u3002</p><h4 id="\u91C7\u7528dart\u8BED\u8A00\u5F00\u53D1" tabindex="-1"><a class="header-anchor" href="#\u91C7\u7528dart\u8BED\u8A00\u5F00\u53D1" aria-hidden="true">#</a> \u91C7\u7528Dart\u8BED\u8A00\u5F00\u53D1</h4><p>\u8FD9\u4E2A\u662F\u4E00\u4E2A\u5F88\u6709\u610F\u601D\u4F46\u4E5F\u5F88\u6709\u4E89\u8BAE\u7684\u95EE\u9898\uFF0C\u5728\u4E86\u89E3 Flutter \u4E3A\u4EC0\u4E48\u9009\u62E9\u4E86 Dart \u800C\u4E0D\u662F JavaScript \u4E4B\u524D\u6211\u4EEC\u5148\u6765\u4ECB\u7ECD\u4E00\u4E0B\u4E4B\u524D\u63D0\u5230\u8FC7\u7684\u4E24\u4E2A\u6982\u5FF5\uFF1AJIT \u548C AOT\u3002</p><p>\u7A0B\u5E8F\u4E3B\u8981\u6709\u4E24\u79CD\u8FD0\u884C\u65B9\u5F0F\uFF1A\u9759\u6001\u7F16\u8BD1\u4E0E\u52A8\u6001\u89E3\u91CA\u3002\u9759\u6001\u7F16\u8BD1\u7684\u7A0B\u5E8F\u5728\u6267\u884C\u524D\u7A0B\u5E8F\u4F1A\u88AB\u63D0\u524D\u7F16\u8BD1\u4E3A\u673A\u5668\u7801\uFF08\u6216\u4E2D\u95F4\u5B57\u8282\u7801\uFF09\uFF0C\u901A\u5E38\u5C06\u8FD9\u79CD\u7C7B\u578B\u79F0\u4E3A<strong>AOT</strong> \uFF08Ahead of time\uFF09\u5373 \u201C\u63D0\u524D\u7F16\u8BD1\u201D\u3002\u800C\u89E3\u91CA\u6267\u884C\u5219\u662F\u5728\u8FD0\u884C\u65F6\u5C06\u6E90\u7801\u5B9E\u65F6\u7FFB\u8BD1\u4E3A\u673A\u5668\u7801\u6765\u6267\u884C\uFF0C\u901A\u5E38\u5C06\u8FD9\u79CD\u7C7B\u578B\u79F0\u4E3A<strong>JIT</strong>\uFF08Just-in-time\uFF09\u5373\u201C\u5373\u65F6\u7F16\u8BD1\u201D\u3002</p><p>AOT \u7A0B\u5E8F\u7684\u5178\u578B\u4EE3\u8868\u662F\u7528 C/C++ \u5F00\u53D1\u7684\u5E94\u7528\uFF0C\u5B83\u4EEC\u5FC5\u987B\u5728\u6267\u884C\u524D\u7F16\u8BD1\u6210\u673A\u5668\u7801\uFF1B\u800CJIT\u7684\u4EE3\u8868\u5219\u975E\u5E38\u591A\uFF0C\u5982JavaScript\u3001python\u7B49\uFF0C\u4E8B\u5B9E\u4E0A\uFF0C\u6240\u6709\u811A\u672C\u8BED\u8A00\u90FD\u652F\u6301 JIT \u6A21\u5F0F\u3002\u4F46\u9700\u8981\u6CE8\u610F\u7684\u662F JIT \u548C AOT \u6307\u7684\u662F\u7A0B\u5E8F\u8FD0\u884C\u65B9\u5F0F\uFF0C\u548C\u7F16\u7A0B\u8BED\u8A00\u5E76\u975E\u5F3A\u5173\u8054\u7684\uFF0C\u6709\u4E9B\u8BED\u8A00\u65E2\u53EF\u4EE5\u4EE5 JIT \u65B9\u5F0F\u8FD0\u884C\u4E5F\u53EF\u4EE5\u4EE5 AOT \u65B9\u5F0F\u8FD0\u884C\uFF0C\u5982Python\uFF0C\u5B83\u53EF\u4EE5\u5728\u7B2C\u4E00\u6B21\u6267\u884C\u65F6\u7F16\u8BD1\u6210\u4E2D\u95F4\u5B57\u8282\u7801\uFF0C\u7136\u540E\u5728\u4E4B\u540E\u6267\u884C\u65F6\u518D\u5C06\u5B57\u8282\u7801\u5B9E\u65BD\u8F6C\u4E3A\u673A\u5668\u7801\u6267\u884C\u3002\u4E5F\u8BB8\u6709\u4EBA\u4F1A\u8BF4\uFF0C\u4E2D\u95F4\u5B57\u8282\u7801\u5E76\u975E\u673A\u5668\u7801\uFF0C\u5728\u7A0B\u5E8F\u6267\u884C\u65F6\u4ECD\u7136\u9700\u8981\u52A8\u6001\u5C06\u5B57\u8282\u7801\u8F6C\u4E3A\u673A\u5668\u7801\uFF0C\u8FD9\u4E0D\u5E94\u8BE5\u662F JIT \u5417 ? \u662F\u8FD9\u6837\uFF0C\u4F46\u901A\u5E38\u6211\u4EEC\u533A\u5206\u662F\u5426\u4E3AAOT \u7684\u6807\u51C6\u5C31\u662F\u770B\u4EE3\u7801\u5728\u6267\u884C\u4E4B\u524D<strong>\u662F\u5426\u9700\u8981\u7F16\u8BD1</strong>\uFF0C\u53EA\u8981\u9700\u8981\u7F16\u8BD1\uFF0C\u65E0\u8BBA\u5176\u7F16\u8BD1\u4EA7\u7269\u662F\u5B57\u8282\u7801\u8FD8\u662F\u673A\u5668\u7801\uFF0C\u90FD\u5C5E\u4E8EAOT\u3002\u5728\u6B64\uFF0C\u8BFB\u8005\u4E0D\u5FC5\u7EA0\u7ED3\u4E8E\u6982\u5FF5\uFF0C\u6982\u5FF5\u5C31\u662F\u4E3A\u4E86\u4F20\u8FBE\u7CBE\u795E\u800C\u53D1\u660E\u7684\uFF0C\u53EA\u8981\u8BFB\u8005\u80FD\u591F\u7406\u89E3\u5176\u539F\u7406\u5373\u53EF\uFF0C\u5F97\u5176\u795E\u5FD8\u5176\u5F62\u3002</p><p>\u73B0\u5728\u6211\u4EEC\u770B\u770B Flutter \u4E3A\u4EC0\u4E48\u9009\u62E9 Dart \u8BED\u8A00\uFF1F\u7B14\u8005\u6839\u636E\u5B98\u65B9\u89E3\u91CA\u4EE5\u53CA\u81EA\u5DF1\u5BF9 Flutter \u7684\u7406\u89E3\u603B\u7ED3\u4E86\u4EE5\u4E0B\u51E0\u6761\uFF08\u7531\u4E8E\u5176\u5B83\u8DE8\u5E73\u53F0\u6846\u67B6\u90FD\u5C06 JavaScript \u4F5C\u4E3A\u5176\u5F00\u53D1\u8BED\u8A00\uFF0C\u6240\u4EE5\u4E3B\u8981\u5C06 Dart \u548C JavaScript \u505A\u4E00\u4E2A\u5BF9\u6BD4\uFF09\uFF1A</p><ol><li><p><strong>\u5F00\u53D1\u6548\u7387\u9AD8</strong>\u3002</p><p>Dart \u8FD0\u884C\u65F6\u548C\u7F16\u8BD1\u5668\u652F\u6301 Flutter \u7684\u4E24\u4E2A\u5173\u952E\u7279\u6027\u7684\u7EC4\u5408\uFF1A</p><ul><li><p><strong>\u57FA\u4E8E JIT \u7684\u5FEB\u901F\u5F00\u53D1\u5468\u671F</strong>\uFF1AFlutter \u5728\u5F00\u53D1\u9636\u6BB5\u91C7\u7528\uFF0C\u91C7\u7528 JIT \u6A21\u5F0F\uFF0C\u8FD9\u6837\u5C31\u907F\u514D\u4E86\u6BCF\u6B21\u6539\u52A8\u90FD\u8981\u8FDB\u884C\u7F16\u8BD1\uFF0C\u6781\u5927\u7684\u8282\u7701\u4E86\u5F00\u53D1\u65F6\u95F4\uFF1B</p></li><li><p><strong>\u57FA\u4E8E AOT \u7684\u53D1\u5E03\u5305</strong>: Flutter \u5728\u53D1\u5E03\u65F6\u53EF\u4EE5\u901A\u8FC7 AOT \u751F\u6210\u9AD8\u6548\u7684\u673A\u5668\u7801\u4EE5\u4FDD\u8BC1\u5E94\u7528\u6027\u80FD\u3002\u800C JavaScript \u5219\u4E0D\u5177\u6709\u8FD9\u4E2A\u80FD\u529B\u3002</p></li></ul></li><li><p><strong>\u9AD8\u6027\u80FD</strong>\u3002</p><p>Flutter \u65E8\u5728\u63D0\u4F9B\u6D41\u7545\u3001\u9AD8\u4FDD\u771F\u7684\u7684 UI \u4F53\u9A8C\u3002\u4E3A\u4E86\u5B9E\u73B0\u8FD9\u4E00\u70B9\uFF0CFlutter \u4E2D\u9700\u8981\u80FD\u591F\u5728\u6BCF\u4E2A\u52A8\u753B\u5E27\u4E2D\u8FD0\u884C\u5927\u91CF\u7684\u4EE3\u7801\u3002\u8FD9\u610F\u5473\u7740\u9700\u8981\u4E00\u79CD\u65E2\u80FD\u63D0\u4F9B\u9AD8\u6027\u80FD\u7684\u8BED\u8A00\uFF0C\u800C\u4E0D\u4F1A\u51FA\u73B0\u4F1A\u4E22\u5E27\u7684\u5468\u671F\u6027\u6682\u505C\uFF0C\u800C Dart \u652F\u6301 AOT\uFF0C\u5728\u8FD9\u4E00\u70B9\u4E0A\u53EF\u4EE5\u505A\u7684\u6BD4 JavaScript \u66F4\u597D\u3002</p></li><li><p><strong>\u5FEB\u901F\u5185\u5B58\u5206\u914D</strong>\u3002</p><p>Flutter \u6846\u67B6\u4F7F\u7528\u51FD\u6570\u5F0F\u6D41\uFF0C\u8FD9\u4F7F\u5F97\u5B83\u5728\u5F88\u5927\u7A0B\u5EA6\u4E0A\u4F9D\u8D56\u4E8E\u5E95\u5C42\u7684\u5185\u5B58\u5206\u914D\u5668\u3002\u56E0\u6B64\uFF0C\u62E5\u6709\u4E00\u4E2A\u80FD\u591F\u6709\u6548\u5730\u5904\u7406\u7410\u788E\u4EFB\u52A1\u7684\u5185\u5B58\u5206\u914D\u5668\u5C06\u663E\u5F97\u5341\u5206\u91CD\u8981\uFF0C\u5728\u7F3A\u4E4F\u6B64\u529F\u80FD\u7684\u8BED\u8A00\u4E2D\uFF0CFlutter \u5C06\u65E0\u6CD5\u6709\u6548\u5730\u5DE5\u4F5C\u3002\u5F53\u7136 Chrome V8 \u7684 JavaScript \u5F15\u64CE\u5728\u5185\u5B58\u5206\u914D\u4E0A\u4E5F\u5DF2\u7ECF\u505A\u7684\u5F88\u597D\uFF0C\u4E8B\u5B9E\u4E0A Dart \u5F00\u53D1\u56E2\u961F\u7684\u5F88\u591A\u6210\u5458\u90FD\u662F\u6765\u81EAChrome \u56E2\u961F\u7684\uFF0C\u6240\u4EE5\u5728\u5185\u5B58\u5206\u914D\u4E0A Dart \u5E76\u4E0D\u80FD\u4F5C\u4E3A\u8D85\u8D8A JavaScript \u7684\u4F18\u52BF\uFF0C\u800C\u5BF9\u4E8EFlutter\u6765\u8BF4\uFF0C\u5B83\u9700\u8981\u8FD9\u6837\u7684\u7279\u6027\uFF0C\u800C Dart \u4E5F\u6B63\u597D\u6EE1\u8DB3\u800C\u5DF2\u3002</p></li><li><p><strong>\u7C7B\u578B\u5B89\u5168\u548C\u7A7A\u5B89\u5168</strong>\u3002</p><p>\u7531\u4E8E Dart \u662F\u7C7B\u578B\u5B89\u5168\u7684\u8BED\u8A00\uFF0C\u4E14 2.12 \u7248\u672C\u540E\u4E5F\u652F\u6301\u4E86\u7A7A\u5B89\u5168\u7279\u6027\uFF0C\u6240\u4EE5 Dart \u652F\u6301\u9759\u6001\u7C7B\u578B\u68C0\u6D4B\uFF0C\u53EF\u4EE5\u5728\u7F16\u8BD1\u524D\u53D1\u73B0\u4E00\u4E9B\u7C7B\u578B\u7684\u9519\u8BEF\uFF0C\u5E76\u6392\u9664\u6F5C\u5728\u95EE\u9898\uFF0C\u8FD9\u4E00\u70B9\u5BF9\u4E8E\u524D\u7AEF\u5F00\u53D1\u8005\u6765\u8BF4\u53EF\u80FD\u4F1A\u66F4\u5177\u6709\u5438\u5F15\u529B\u3002\u4E0E\u4E4B\u4E0D\u540C\u7684\uFF0CJavaScript \u662F\u4E00\u4E2A\u5F31\u7C7B\u578B\u8BED\u8A00\uFF0C\u4E5F\u56E0\u6B64\u524D\u7AEF\u793E\u533A\u51FA\u73B0\u4E86\u5F88\u591A\u7ED9 JavaScript \u4EE3\u7801\u6DFB\u52A0\u9759\u6001\u7C7B\u578B\u68C0\u6D4B\u7684\u6269\u5C55\u8BED\u8A00\u548C\u5DE5\u5177\uFF0C\u5982\uFF1A\u5FAE\u8F6F\u7684 TypeScript \u4EE5\u53CAFacebook \u7684 Flow\u3002\u76F8\u6BD4\u4E4B\u4E0B\uFF0CDart \u672C\u8EAB\u5C31\u652F\u6301\u9759\u6001\u7C7B\u578B\uFF0C\u8FD9\u662F\u5B83\u7684\u4E00\u4E2A\u91CD\u8981\u4F18\u52BF\u3002</p></li><li><p><strong>Dart \u56E2\u961F\u5C31\u5728\u4F60\u8EAB\u8FB9</strong>\u3002</p><p>\u770B\u4F3C\u4E0D\u8D77\u773C\uFF0C\u5B9E\u5219\u4E3E\u8DB3\u8F7B\u91CD\u3002\u7531\u4E8E\u6709 Dart \u56E2\u961F\u7684\u79EF\u6781\u6295\u5165\uFF0CFlutter \u56E2\u961F\u53EF\u4EE5\u83B7\u5F97\u66F4\u591A\u3001\u66F4\u65B9\u4FBF\u7684\u652F\u6301\uFF0C\u6B63\u5982Flutter \u5B98\u7F51\u6240\u8FF0\u201C\u6211\u4EEC\u6B63\u4E0E Dart \u793E\u533A\u8FDB\u884C\u5BC6\u5207\u5408\u4F5C\uFF0C\u4EE5\u6539\u8FDB Dart \u5728 Flutter \u4E2D\u7684\u4F7F\u7528\u3002\u4F8B\u5982\uFF0C\u5F53\u6211\u4EEC\u6700\u521D\u91C7\u7528 Dart \u65F6\uFF0C\u8BE5\u8BED\u8A00\u5E76\u6CA1\u6709\u63D0\u4F9B\u751F\u6210\u539F\u751F\u4E8C\u8FDB\u5236\u6587\u4EF6\u7684\u5DE5\u5177\u94FE\uFF08\u8FD9\u5BF9\u4E8E\u5B9E\u73B0\u53EF\u9884\u6D4B\u7684\u9AD8\u6027\u80FD\u5177\u6709\u5F88\u5927\u7684\u5E2E\u52A9\uFF09\uFF0C\u4F46\u662F\u73B0\u5728\u5B83\u5B9E\u73B0\u4E86\uFF0C\u56E0\u4E3A Dart \u56E2\u961F\u4E13\u95E8\u4E3A Flutter \u6784\u5EFA\u4E86\u5B83\u3002\u540C\u6837\uFF0CDart VM \u4E4B\u524D\u5DF2\u7ECF\u9488\u5BF9\u541E\u5410\u91CF\u8FDB\u884C\u4E86\u4F18\u5316\uFF0C\u4F46\u56E2\u961F\u73B0\u5728\u6B63\u5728\u4F18\u5316 VM \u7684\u5EF6\u8FDF\u65F6\u95F4\uFF0C\u8FD9\u5BF9\u4E8E Flutter \u7684\u5DE5\u4F5C\u8D1F\u8F7D\u66F4\u4E3A\u91CD\u8981\u3002\u201D</p></li></ol><h4 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h4><p>\u672C\u8282\u4E3B\u8981\u4ECB\u7ECD\u4E86\u4E00\u4E0B Flutter \u7684\u7279\u70B9\uFF0C\u5982\u679C\u4F60\u611F\u5230\u6709\u4E9B\u70B9\u8FD8\u4E0D\u662F\u5F88\u597D\u7406\u89E3\uFF0C\u4E0D\u7528\u7740\u6025\uFF0C\u968F\u7740\u65E5\u540E\u5BF9 Flutter \u7EC6\u8282\u7684\u4E86\u89E3\uFF0C\u518D\u56DE\u8FC7\u5934\u6765\u770B\uFF0C\u76F8\u4FE1\u4F60\u4F1A\u6709\u66F4\u6DF1\u7684\u4F53\u4F1A\u3002</p><h2 id="_1-2-2-flutter\u6846\u67B6\u7ED3\u6784" tabindex="-1"><a class="header-anchor" href="#_1-2-2-flutter\u6846\u67B6\u7ED3\u6784" aria-hidden="true">#</a> 1.2.2 Flutter\u6846\u67B6\u7ED3\u6784</h2><p>\u672C\u8282\u6211\u4EEC\u5148\u5BF9 Flutter \u7684\u6846\u67B6\u505A\u4E00\u4E2A\u6574\u4F53\u4ECB\u7ECD\uFF0C\u65E8\u5728\u8BA9\u8BFB\u8005\u5FC3\u4E2D\u6709\u4E00\u4E2A\u6574\u4F53\u7684\u5370\u8C61\uFF0C\u8FD9\u5BF9\u521D\u5B66\u8005\u6765\u8BF4\u975E\u5E38\u91CD\u8981\u3002\u5982\u679C\u4E00\u4E0B\u5B50\u4FBF\u6DF1\u5165\u5230 Flutter \u4E2D\uFF0C\u5C31\u4F1A\u50CF\u662F\u4E00\u4E2A\u5728\u6C99\u6F20\u4E2D\u6CA1\u6709\u5730\u56FE\u7684\u4EBA\uFF0C\u5373\u4F7F\u53EF\u4EE5\u627E\u5230\u4E00\u4E2A\u7EFF\u6D32\uFF0C\u4F46\u662F\u4ED6\u4E5F\u4E0D\u4F1A\u77E5\u9053\u4E0B\u4E00\u4E2A\u7EFF\u6D32\u5728\u54EA\u3002\u56E0\u6B64\uFF0C\u65E0\u8BBA\u5B66\u4EC0\u4E48\u6280\u672F\uFF0C\u90FD\u8981\u5148\u6709\u4E00\u5F20\u6E05\u6670\u7684\u201C\u5730\u56FE\u201D\uFF0C\u800C\u6211\u4EEC\u7684\u5B66\u4E60\u8FC7\u7A0B\u5C31\u662F\u201C\u6309\u56FE\u7D22\u9AA5\u201D\uFF0C\u8FD9\u6837\u6211\u4EEC\u624D\u4E0D\u4F1A\u9677\u4E8E\u7EC6\u8282\u800C\u201C\u76EE\u65E0\u5168\u725B\u201D\u3002\u8A00\u5F52\u6B63\u4F20\uFF0C\u6211\u4EEC\u770B\u4E00\u4E0B Flutter \u5B98\u65B9\u63D0\u4F9B\u7684 Flutter \u6846\u67B6\u56FE\uFF0C\u5982\u56FE1-1\u6240\u793A\uFF1A</p><p><img src="'+d+'" alt="\u56FE1-1"></p><p>\u7B80\u5355\u6765\u8BB2\uFF0CFlutter \u4ECE\u4E0A\u5230\u4E0B\u53EF\u4EE5\u5206\u4E3A\u4E09\u5C42\uFF1A\u6846\u67B6\u5C42\u3001\u5F15\u64CE\u5C42\u548C\u5D4C\u5165\u5C42\uFF0C\u4E0B\u9762\u6211\u4EEC\u5206\u522B\u4ECB\u7ECD\uFF1A</p><h3 id="\u6846\u67B6\u5C42" tabindex="-1"><a class="header-anchor" href="#\u6846\u67B6\u5C42" aria-hidden="true">#</a> \u6846\u67B6\u5C42</h3><p>Flutter Framework\uFF0C\u5373\u6846\u67B6\u5C42\u3002\u8FD9\u662F\u4E00\u4E2A\u7EAF Dart\u5B9E\u73B0\u7684 SDK\uFF0C\u5B83\u5B9E\u73B0\u4E86\u4E00\u5957\u57FA\u7840\u5E93\uFF0C\u81EA\u5E95\u5411\u4E0A\uFF0C\u6211\u4EEC\u6765\u7B80\u5355\u4ECB\u7ECD\u4E00\u4E0B\uFF1A</p><ul><li>\u5E95\u4E0B\u4E24\u5C42\uFF08Foundation \u548C Animation\u3001Painting\u3001Gestures\uFF09\u5728 Google \u7684\u4E00\u4E9B\u89C6\u9891\u4E2D\u88AB\u5408\u5E76\u4E3A\u4E00\u4E2Adart UI\u5C42\uFF0C\u5BF9\u5E94\u7684\u662FFlutter\u4E2D\u7684<code>dart:ui</code>\u5305\uFF0C\u5B83\u662F Flutter Engine \u66B4\u9732\u7684\u5E95\u5C42UI\u5E93\uFF0C\u63D0\u4F9B\u52A8\u753B\u3001\u624B\u52BF\u53CA\u7ED8\u5236\u80FD\u529B\u3002</li><li>Rendering \u5C42\uFF0C\u5373\u6E32\u67D3\u5C42\uFF0C\u8FD9\u4E00\u5C42\u662F\u4E00\u4E2A\u62BD\u8C61\u7684\u5E03\u5C40\u5C42\uFF0C\u5B83\u4F9D\u8D56\u4E8E Dart UI \u5C42\uFF0C\u6E32\u67D3\u5C42\u4F1A\u6784\u5EFA\u4E00\u68F5\u7531\u53EF\u6E32\u67D3\u5BF9\u8C61\u7684\u7EC4\u6210\u7684<strong>\u6E32\u67D3\u6811</strong>\uFF0C\u5F53\u52A8\u6001\u66F4\u65B0\u8FD9\u4E9B\u5BF9\u8C61\u65F6\uFF0C\u6E32\u67D3\u6811\u4F1A\u627E\u51FA\u53D8\u5316\u7684\u90E8\u5206\uFF0C\u7136\u540E\u66F4\u65B0\u6E32\u67D3\u3002\u6E32\u67D3\u5C42\u53EF\u4EE5\u8BF4\u662FFlutter \u6846\u67B6\u5C42\u4E2D\u6700\u6838\u5FC3\u7684\u90E8\u5206\uFF0C\u5B83\u9664\u4E86\u786E\u5B9A\u6BCF\u4E2A\u6E32\u67D3\u5BF9\u8C61\u7684\u4F4D\u7F6E\u3001\u5927\u5C0F\u4E4B\u5916\u8FD8\u8981\u8FDB\u884C\u5750\u6807\u53D8\u6362\u3001\u7ED8\u5236\uFF08\u8C03\u7528\u5E95\u5C42 dart:ui \uFF09\u3002</li><li>Widgets \u5C42\u662F Flutter \u63D0\u4F9B\u7684\u7684\u4E00\u5957\u57FA\u7840\u7EC4\u4EF6\u5E93\uFF0C\u5728\u57FA\u7840\u7EC4\u4EF6\u5E93\u4E4B\u4E0A\uFF0CFlutter \u8FD8\u63D0\u4F9B\u4E86 Material \u548C Cupertino \u4E24\u79CD\u89C6\u89C9\u98CE\u683C\u7684\u7EC4\u4EF6\u5E93\uFF0C\u5B83\u4EEC\u5206\u522B\u5B9E\u73B0\u4E86 Material \u548C iOS \u8BBE\u8BA1\u89C4\u8303\u3002</li></ul>',26),h=t("Flutter \u6846\u67B6\u76F8\u5BF9\u8F83\u5C0F\uFF0C\u56E0\u4E3A\u4E00\u4E9B\u5F00\u53D1\u8005\u53EF\u80FD\u4F1A\u4F7F\u7528\u5230\u7684\u66F4\u9AD8\u5C42\u7EA7\u7684\u529F\u80FD\u5DF2\u7ECF\u88AB\u62C6\u5206\u5230\u4E0D\u540C\u7684\u8F6F\u4EF6\u5305\u4E2D\uFF0C\u4F7F\u7528 Dart \u548C Flutter \u7684\u6838\u5FC3\u5E93\u5B9E\u73B0\uFF0C\u5176\u4E2D\u5305\u62EC\u5E73\u53F0\u63D2\u4EF6\uFF0C\u4F8B\u5982 "),c={href:"https://pub.flutter-io.cn/packages/camera",target:"_blank",rel:"noopener noreferrer"},F=t("camera"),_=t(" \u548C "),g={href:"https://pub.flutter-io.cn/packages/webview_flutter",target:"_blank",rel:"noopener noreferrer"},f=t("webview"),D=t("\uFF0C\u4EE5\u53CA\u548C\u5E73\u53F0\u65E0\u5173\u7684\u529F\u80FD\uFF0C\u4F8B\u5982 "),S={href:"https://pub.flutter-io.cn/packages/animations",target:"_blank",rel:"noopener noreferrer"},b=t("animations"),v=t("\u3002"),m=i('<p>\u6211\u4EEC\u8FDB\u884CFlutter \u5F00\u53D1\u65F6\uFF0C\u5927\u591A\u6570\u65F6\u5019\u90FD\u662F\u548C Flutter Framework \u6253\u4EA4\u9053\u3002</p><h3 id="\u5F15\u64CE\u5C42" tabindex="-1"><a class="header-anchor" href="#\u5F15\u64CE\u5C42" aria-hidden="true">#</a> \u5F15\u64CE\u5C42</h3><p>Engine\uFF0C\u5373\u5F15\u64CE\u5C42\u3002\u6BEB\u65E0\u7591\u95EE\u662F Flutter \u7684\u6838\u5FC3\uFF0C \u8BE5\u5C42\u4E3B\u8981\u662F C++ \u5B9E\u73B0\uFF0C\u5176\u4E2D\u5305\u62EC\u4E86 Skia \u5F15\u64CE\u3001Dart \u8FD0\u884C\u65F6\u3001\u6587\u5B57\u6392\u7248\u5F15\u64CE\u7B49\u3002\u5728\u4EE3\u7801\u8C03\u7528 <code>dart:ui </code>\u5E93\u65F6\uFF0C\u8C03\u7528\u6700\u7EC8\u4F1A\u8D70\u5230\u5F15\u64CE\u5C42\uFF0C\u7136\u540E\u5B9E\u73B0\u771F\u6B63\u7684\u7ED8\u5236\u548C\u663E\u793A\u3002</p><h3 id="\u5D4C\u5165\u5C42" tabindex="-1"><a class="header-anchor" href="#\u5D4C\u5165\u5C42" aria-hidden="true">#</a> \u5D4C\u5165\u5C42</h3><p>Embedder\uFF0C\u5373\u5D4C\u5165\u5C42\u3002Flutter \u6700\u7EC8\u6E32\u67D3\u3001\u4EA4\u4E92\u662F\u8981\u4F9D\u8D56\u5176\u6240\u5728\u5E73\u53F0\u7684\u64CD\u4F5C\u7CFB\u7EDF API\uFF0C\u5D4C\u5165\u5C42\u4E3B\u8981\u662F\u5C06 Flutter \u5F15\u64CE \u201D\u5B89\u88C5\u201C \u5230\u7279\u5B9A\u5E73\u53F0\u4E0A\u3002\u5D4C\u5165\u5C42\u91C7\u7528\u4E86\u5F53\u524D\u5E73\u53F0\u7684\u8BED\u8A00\u7F16\u5199\uFF0C\u4F8B\u5982 Android \u4F7F\u7528\u7684\u662F Java \u548C C++\uFF0C iOS \u548C macOS \u4F7F\u7528\u7684\u662F Objective-C \u548C Objective-C++\uFF0CWindows \u548C Linux \u4F7F\u7528\u7684\u662F C++\u3002 Flutter \u4EE3\u7801\u53EF\u4EE5\u901A\u8FC7\u5D4C\u5165\u5C42\uFF0C\u4EE5\u6A21\u5757\u65B9\u5F0F\u96C6\u6210\u5230\u73B0\u6709\u7684\u5E94\u7528\u4E2D\uFF0C\u4E5F\u53EF\u4EE5\u4F5C\u4E3A\u5E94\u7528\u7684\u4E3B\u4F53\u3002Flutter \u672C\u8EAB\u5305\u542B\u4E86\u5404\u4E2A\u5E38\u89C1\u5E73\u53F0\u7684\u5D4C\u5165\u5C42\uFF0C\u5047\u5982\u4EE5\u540E Flutter \u8981\u652F\u6301\u65B0\u7684\u5E73\u53F0\uFF0C\u5219\u9700\u8981\u9488\u5BF9\u8BE5\u65B0\u7684\u5E73\u53F0\u7F16\u5199\u4E00\u4E2A\u5D4C\u5165\u5C42\u3002</p><h3 id="\u603B\u7ED3-1" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3-1" aria-hidden="true">#</a> \u603B\u7ED3</h3><p>\u8FD9\u90E8\u5206\uFF0C\u6211\u4EEC\u6574\u4F53\u4E0A\u4ECB\u7ECD\u4E86 Flutter \u6846\u67B6\u7684\u5206\u5C42\uFF0C\u4ECE\u4E0A\u5230\u4E0B\u4E3A\uFF1A\u6846\u67B6\u5C42\u3001\u5F15\u64CE\u5C42\u548C\u5D4C\u5165\u5C42\uFF0C\u8BFB\u8005\u4E00\u5B9A\u8981\u7262\u8BB0\u3002</p><h2 id="_1-2-3-\u5982\u4F55\u5B66\u4E60flutter" tabindex="-1"><a class="header-anchor" href="#_1-2-3-\u5982\u4F55\u5B66\u4E60flutter" aria-hidden="true">#</a> 1.2.3 \u5982\u4F55\u5B66\u4E60Flutter</h2><p>\u672C\u8282\u7ED9\u5927\u5BB6\u4E00\u4E9B\u5B66\u4E60\u5EFA\u8BAE\uFF0C\u5206\u4EAB\u4E00\u4E0B\u7B14\u8005\u5728\u5B66\u4E60Flutter\u4E2D\u7684\u4E00\u4E9B\u5FC3\u5F97\uFF0C\u5E0C\u671B\u53EF\u4EE5\u5E2E\u52A9\u4F60\u63D0\u9AD8\u5B66\u4E60\u6548\u7387\u3002</p><h3 id="\u8D44\u6E90" tabindex="-1"><a class="header-anchor" href="#\u8D44\u6E90" aria-hidden="true">#</a> \u8D44\u6E90</h3><ul><li><p><strong>\u5B98\u7F51</strong>\uFF1A\u9605\u8BFBFlutter\u5B98\u7F51\u7684\u8D44\u6E90\u662F\u5FEB\u901F\u5165\u95E8\u7684\u6700\u4F73\u65B9\u5F0F\uFF0C\u540C\u65F6\u5B98\u7F51\u4E5F\u662F\u4E86\u89E3\u6700\u65B0Flutter\u53D1\u5C55\u52A8\u6001\u7684\u5730\u65B9\uFF0C\u7531\u4E8E\u76EE\u524D Flutter \u4ECD\u7136\u5904\u4E8E\u5FEB\u901F\u53D1\u5C55\u9636\u6BB5\uFF0C\u6240\u4EE5\u5EFA\u8BAE\u8BFB\u8005\u8FD8\u662F\u65F6\u4E0D\u65F6\u7684\u53BB\u5B98\u7F51\u770B\u770B\u6709\u6CA1\u6709\u65B0\u7684\u52A8\u6001\u3002</p></li><li><p><strong>\u6E90\u7801\u53CA\u6CE8\u91CA</strong>\uFF1A<strong>\u6E90\u7801\u6CE8\u91CA\u5E94\u4F5C\u4E3A\u5B66\u4E60 Flutter \u7684\u7B2C\u4E00\u6587\u6863</strong>\uFF0CFlutter SDK \u7684\u6E90\u7801\u662F\u5305\u542B\u5728 Flutter \u5DE5\u7A0B\u4E2D\u7684\u7684\uFF0C\u5E76\u4E14\u6CE8\u91CA\u975E\u5E38\u8BE6\u7EC6\u4E14\u6709\u5F88\u591A\u793A\u4F8B\uFF0C\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7 IDE \u7684\u8DF3\u8F6C\u529F\u80FD\u5FEB\u901F\u5B9A\u4F4D\u5230\u6E90\u7801\u3002\u5B9E\u9645\u4E0A\uFF0CFlutter \u5B98\u65B9\u7684\u7EC4\u4EF6\u6587\u6863\u5C31\u662F\u901A\u8FC7\u6CE8\u91CA\u751F\u6210\u7684\u3002\u6839\u636E\u7B14\u8005\u7ECF\u9A8C\uFF0C\u6E90\u7801\u7ED3\u5408\u6CE8\u91CA\u53EF\u4EE5\u5E2E\u6211\u4EEC\u89E3\u51B3\u5927\u591A\u6570\u95EE\u9898\u3002</p></li><li><p><strong>Github</strong>\uFF1A\u5982\u679C\u9047\u5230\u7684\u95EE\u9898\u5728StackOverflow\u4E0A\u4E5F\u6CA1\u6709\u627E\u5230\u7B54\u6848\uFF0C\u53EF\u4EE5\u53BB Github flutter \u9879\u76EE\u4E0B\u63D0 issue\u3002</p></li><li><p><strong>Gallery\u6E90\u7801</strong>\uFF1AGallery \u662F Flutter \u5B98\u65B9\u793A\u4F8B APP\uFF0C\u91CC\u9762\u6709\u4E30\u5BCC\u7684\u793A\u4F8B\uFF0C\u8BFB\u8005\u53EF\u4EE5\u5728\u7F51\u4E0A\u4E0B\u8F7D\u5B89\u88C5\u3002Gallery \u7684\u6E90\u7801\u5728 Flutter \u6E90\u7801 \u201Cexamples\u201D \u76EE\u5F55\u4E0B\u3002</p></li><li><p><strong>StackOverflow</strong>\uFF1A StackOverflow \u662F\u76EE\u524D\u5168\u7403\u6700\u5927\u7684\u7A0B\u5E8F\u5458\u95EE\u7B54\u793E\u533A\uFF0C\u73B0\u5728\u4E5F\u662F\u6D3B\u8DC3\u5EA6\u6700\u9AD8\u7684 Flutter \u95EE\u7B54\u793E\u533A\u3002StackOverflow \u4E0A\u9762\u9664\u4E86\u4E16\u754C\u5404\u5730\u7684 Flutter\u5F00\u53D1\u8005\u4F1A\u5728\u4E0A\u9762\u4EA4\u6D41\u4E4B\u5916\uFF0CFlutter \u5F00\u53D1\u56E2\u961F\u7684\u6210\u5458\u4E5F\u7ECF\u5E38\u4F1A\u5728\u4E0A\u9762\u56DE\u7B54\u95EE\u9898\u3002</p></li></ul><h3 id="\u603B\u7ED3-2" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3-2" aria-hidden="true">#</a> \u603B\u7ED3</h3><p>\u6709\u4E86\u8D44\u6599\u548C\u793E\u533A\u540E\uFF0C\u5BF9\u4E8E Flutter \u7684\u5B66\u4E60\u8005\u6765\u8BF4\uFF0C\u6700\u91CD\u8981\u7684\u8FD8\u662F\u8981\u591A\u52A8\u624B\u3001\u591A\u5B9E\u8DF5\u3002\u5728\u672C\u4E66\u540E\u9762\u7684\u7AE0\u8282\u4E2D\uFF0C\u5E0C\u671B\u8BFB\u8005\u80FD\u591F\u4EB2\u81EA\u52A8\u624B\u5199\u4E00\u4E0B\u793A\u4F8B\u3002</p><h2 id="\u6700\u540E" tabindex="-1"><a class="header-anchor" href="#\u6700\u540E" aria-hidden="true">#</a> \u6700\u540E</h2><p>Flutter \u6846\u67B6\u672C\u8EAB\u6709\u7740\u826F\u597D\u7684\u5206\u5C42\u8BBE\u8BA1\uFF0C\u672C\u8282\u65E8\u5728\u8BA9\u8BFB\u8005\u5BF9 Flutter \u6574\u4F53\u6846\u67B6\u6709\u4E2A\u5927\u6982\u7684\u5370\u8C61\uFF0C\u76F8\u4FE1\u5230\u73B0\u5728\u4E3A\u6B62\uFF0C\u8BFB\u8005\u5DF2\u7ECF\u5BF9 Flutter \u6709\u4E00\u4E2A\u521D\u59CB\u5370\u8C61\uFF0C\u5728\u6211\u4EEC\u6B63\u5F0F\u52A8\u624B\u4E4B\u524D\uFF0C\u6211\u4EEC\u8FD8\u9700\u8981\u4E86\u89E3\u4E00\u4E0BFlutter\u7684\u5F00\u53D1\u8BED\u8A00Dart\u3002</p>',15);function J(O,A){const e=n("ExternalLinkIcon");return o(),u("div",null,[p,r("p",null,[h,r("a",c,[F,a(e)]),_,r("a",g,[f,a(e)]),D,r("a",S,[b,a(e)]),v]),m])}var k=l(s,[["render",J],["__file","flutter_intro.html.vue"]]);export{k as default};
